pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Strings.sol";

contract NFTMinter is ERC721URIStorage, Ownable, Pausable, ReentrancyGuard {
    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public constant RESERVED_SUPPLY = 1000;
    uint256 public price = 0.01 ether;
    uint256 public totalSupply = 0;
    string private baseTokenURI;
    address public vaultAddress;

    mapping(address => uint256) private reservedTokens;

    event PriceChanged(uint256 newPrice);
    event TokenMinted(address indexed to, uint256 tokenId);
    event ReservedToken(address indexed to, uint256 amount);
    event Withdrawal(address indexed to, uint256 amount);

    error InsufficientPayment(uint256 required, uint256 received);
    error ExceedsMaximumSupply();
    error ExceedsReservedSupply();

    constructor(string memory _baseTokenURI, address _vaultAddress) ERC721("MyNFT", "MNFT") {
        baseTokenURI = _baseTokenURI;
        vaultAddress = _vaultAddress;
    }

    function setBaseTokenURI(string memory _baseTokenURI) external onlyOwner {
        baseTokenURI = _baseTokenURI;
    }

    function setPrice(uint256 _price) external onlyOwner {
        if (_price == 0) revert InsufficientPayment(1, 0);
        price = _price;
        emit PriceChanged(price);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function reserveTokens(address[] calldata _addresses, uint256[] calldata _amounts) external onlyOwner nonReentrant {
        for (uint256 i = 0; i < _addresses.length; i++) {
            uint256 reservedAmount = reservedTokens[_addresses[i]];
            uint256 requestedAmount = _amounts[i];

            if (reservedAmount + requestedAmount > RESERVED_SUPPLY) revert ExceedsReservedSupply();
            if (totalSupply + requestedAmount > MAX_SUPPLY) revert ExceedsMaximumSupply();

            reservedTokens[_addresses[i]] += requestedAmount;
            totalSupply += requestedAmount;
            emit ReservedToken(_addresses[i], requestedAmount);
        }
    }

    function mintTokens(uint256 _amount) external payable whenNotPaused nonReentrant {
        if (_amount == 0) revert InsufficientPayment(1, 0);
        if (totalSupply + _amount > MAX_SUPPLY) revert ExceedsMaximumSupply();
        if (msg.value < price * _amount) revert InsufficientPayment(price * _amount, msg.value);

        for (uint256 i = 0; i < _amount; i++) {
            uint256 newTokenId = totalSupply + 1;
            totalSupply++;
            _safeMint(msg.sender, newTokenId);
            _setTokenURI(newTokenId, string(abi.encodePacked(baseTokenURI, Strings.toString(newTokenId))));
            emit TokenMinted(msg.sender, newTokenId);
        }
    }

